module.exports = function (app) {
  let unsubscribes = []
  return {
    id: 'crashingplugin',
    name: 'Crashing Plugin',
    schema: function () {
      return { type: 'object', properties: {} }
    },
    start: function () {
      app.subscriptionmanager.subscribe(
        {
          context: '*',
          subscribe: [{ path: 'environment.outside.pressure' }]
        },
        unsubscribes,
        function (err) {
          console.error(err)
        },
        function () {
          throw new TypeError("Cannot read properties of null (reading 'tendency')")
        }
      )
    },
    stop: function () {
      unsubscribes.forEach(function (f) { f() })
      unsubscribes = []
    }
  }
}
